#include <stdio.h>
#include <string.h>
#include <sys/wait.h>

int main(void) {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) { perror("fork"); return 1; }

    if (pid == 0) {
        /* Child: read from pipe */
        close(pipefd[1]);  /* close unused write end */
        char buf[256];
        ssize_t n;
        while ((n = read(pipefd[0], buf, sizeof(buf) - 1)) > 0) {
            buf[n] = '\0';
            printf("Child received: %s", buf);
        }
        /* n == 0 means parent closed write end (EOF) */
        close(pipefd[0]);
        _exit(0);
    }

    /* Parent: write to pipe */
    close(pipefd[0]);  /* close unused read end */
    const char *msgs[] = {"Hello\n", "from\n", "parent\n"};
    for (int i = 0; i < 3; i++)
        write(pipefd[1], msgs[i], strlen(msgs[i]));
    close(pipefd[1]);  /* signals EOF to child */

    wait(NULL);
    return 0;
}

