/* Implements: ls /tmp | sort */
int main(void) {
    int pipefd[2];
    if (pipe(pipefd) == -1) { perror("pipe"); return 1; }

    /* Child 1: ls /tmp (stdout -> pipe) */
    pid_t pid1 = fork();
    if (pid1 == 0) {
        close(pipefd[0]);  /* close read end */
        dup2(pipefd[1], STDOUT_FILENO);
        close(pipefd[1]);  /* close original after dup2 */
        execlp("ls", "ls", "/tmp", (char *)NULL);
        perror("exec ls");
        _exit(127);
    }

    /* Child 2: sort (stdin <- pipe) */
    pid_t pid2 = fork();
    if (pid2 == 0) {
        close(pipefd[1]);  /* close write end */
        dup2(pipefd[0], STDIN_FILENO);
        close(pipefd[0]);  /* close original after dup2 */
        execlp("sort", "sort", (char *)NULL);
        perror("exec sort");
        _exit(127);
    }

    /* Parent: close both pipe ends and wait */
    close(pipefd[0]);
    close(pipefd[1]);
    waitpid(pid1, NULL, 0);
    waitpid(pid2, NULL, 0);

    return 0;
}

