    key_t key = ftok("/tmp", 'A');
    int msqid = msgget(key, IPC_CREAT | 0666);
    if (msqid == -1) { perror("msgget"); return 1; }

    pid_t pid = fork();
    if (pid == 0) {
        /* Child: send messages */
        struct message msg;
        msg.mtype = 1;  /* type 1: request */
        snprintf(msg.mtext, MSG_SIZE, "Hello from child %d", getpid());
        msgsnd(msqid, &msg, strlen(msg.mtext) + 1, 0);

        msg.mtype = 2;  /* type 2: priority */
        snprintf(msg.mtext, MSG_SIZE, "Urgent message!");
        msgsnd(msqid, &msg, strlen(msg.mtext) + 1, 0);

        _exit(0);
    }

    wait(NULL);

    /* Parent: receive type 2 first (selective) */
    struct message msg;
    ssize_t n = msgrcv(msqid, &msg, MSG_SIZE, 2, 0);
    if (n != -1)
        printf("Type 2: %s\n", msg.mtext);

    n = msgrcv(msqid, &msg, MSG_SIZE, 0, 0);  /* any type */
    if (n != -1)
        printf("Any type: %s\n", msg.mtext);

    /* Remove queue */
    msgctl(msqid, IPC_RMID, NULL);
    return 0;
}

