#define SHM_NAME "/demo_shm"
#define SHM_SIZE 4096

int main(void) {
    /* Create shared memory */
    int fd = shm_open(SHM_NAME, O_CREAT | O_RDWR, 0666);
    if (fd == -1) { perror("shm_open"); return 1; }
    ftruncate(fd, SHM_SIZE);

    /* Map into address space */
    char *ptr = mmap(NULL, SHM_SIZE, PROT_READ | PROT_WRITE,
                     MAP_SHARED, fd, 0);
    if (ptr == MAP_FAILED) { perror("mmap"); return 1; }
    close(fd);  /* fd no longer needed after mmap */

    pid_t pid = fork();
    if (pid == 0) {
        /* Child: write to shared memory */
        snprintf(ptr, SHM_SIZE, "Hello from child %d!", getpid());
        munmap(ptr, SHM_SIZE);
        _exit(0);
    }

    wait(NULL);

    /* Parent: read from shared memory */
    printf("Shared memory: %s\n", ptr);

    munmap(ptr, SHM_SIZE);
    shm_unlink(SHM_NAME);
    return 0;
}

