#include <sys/mman.h>
#include <semaphore.h>
#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <sys/wait.h>

#define BUF_SIZE 5
#define ITEMS 20

typedef struct {
    int buffer[BUF_SIZE];
    int in;
    int out;
    sem_t empty;
    sem_t full;
    sem_t mutex;
} shared_data_t;

int main(void) {
    /* Create shared memory for data + semaphores */
    shared_data_t *shm = mmap(NULL, sizeof(shared_data_t),
        PROT_READ | PROT_WRITE, MAP_SHARED | MAP_ANONYMOUS, -1, 0);
    shm->in = 0;
    shm->out = 0;
    sem_init(&shm->empty, 1, BUF_SIZE);  /* pshared=1 for processes */
    sem_init(&shm->full, 1, 0);
    sem_init(&shm->mutex, 1, 1);

    pid_t pid = fork();
    if (pid == 0) {
        /* Child: producer */
        for (int i = 1; i <= ITEMS; i++) {
            sem_wait(&shm->empty);
            sem_wait(&shm->mutex);
            shm->buffer[shm->in] = i;
            printf("Produced: %d\n", i);
            shm->in = (shm->in + 1) % BUF_SIZE;
            sem_post(&shm->mutex);
            sem_post(&shm->full);
        }
        _exit(0);
    }

    /* Parent: consumer */
    for (int i = 0; i < ITEMS; i++) {
        sem_wait(&shm->full);
        sem_wait(&shm->mutex);
        int item = shm->buffer[shm->out];
        printf("Consumed: %d\n", item);
        shm->out = (shm->out + 1) % BUF_SIZE;
        sem_post(&shm->mutex);
        sem_post(&shm->empty);
    }

    wait(NULL);
    sem_destroy(&shm->empty);
    sem_destroy(&shm->full);
    sem_destroy(&shm->mutex);
    munmap(shm, sizeof(shared_data_t));
    return 0;
}

#include <semaphore.h>

sem_t empty, full, mutex;
int buf[5], in = 0, out = 0;

void produce(int item) {
    sem_wait(&empty); sem_wait(&mutex);
    buf[in] = item; in = (in + 1) % 5;
    sem_post(&mutex); sem_post(&full);
}

int consume(void) {
    sem_wait(&full); sem_wait(&mutex);
    int item = buf[out]; out = (out + 1) % 5;
    sem_post(&mutex); sem_post(&empty);
    return item;
}

