#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <string.h>
#include <errno.h>

typedef struct {
    int id;
    char name[32];
    double balance;
} record_t;

int lock_record(int fd, int type, int recnum) {
    struct flock fl;
    fl.l_type = (short)type;
    fl.l_whence = SEEK_SET;
    fl.l_start = (off_t)(recnum * (off_t)sizeof(record_t));
    fl.l_len = sizeof(record_t);
    return fcntl(fd, F_SETLKW, &fl);  /* blocking */
}

int unlock_record(int fd, int recnum) {
    return lock_record(fd, F_UNLCK, recnum);
}

void update_balance(int fd, int recnum, double amount) {
    /* Exclusive lock for write */
    if (lock_record(fd, F_WRLCK, recnum) == -1) {
        if (errno == EDEADLK)
            fprintf(stderr, "Deadlock detected!\n");
        return;
    }

    record_t rec;
    off_t offset = (off_t)(recnum * (off_t)sizeof(record_t));
    pread(fd, &rec, sizeof(rec), offset);
    rec.balance += amount;
    pwrite(fd, &rec, sizeof(rec), offset);

    unlock_record(fd, recnum);
}

int main(void) {
    int fd = open("accounts.db", O_RDWR | O_CREAT, 0644);
    if (fd == -1) { perror("open"); return 1; }

    /* Initialize a record */
    record_t rec = { .id = 1, .name = "Alice", .balance = 1000.0 };
    pwrite(fd, &rec, sizeof(rec), 0);

    /* Update with locking */
    update_balance(fd, 0, -50.0);

    /* Read with shared lock */
    lock_record(fd, F_RDLCK, 0);
    pread(fd, &rec, sizeof(rec), 0);
    printf("%s: $%.2f\n", rec.name, rec.balance);
    unlock_record(fd, 0);

    close(fd);
    unlink("accounts.db");
    return 0;
}

