int try_lock(int fd, int type, off_t start, off_t len) {
    struct flock fl = { .l_type = (short)type, .l_whence = SEEK_SET,
                        .l_start = start, .l_len = len };
    if (fcntl(fd, F_SETLK, &fl) == -1) {
        if (errno == EAGAIN || errno == EACCES)
            return -1;  /* would block */
        perror("fcntl");
        return -1;
    }
    return 0;
}

void unlock(int fd, off_t start, off_t len) {
    struct flock fl = { .l_type = F_UNLCK, .l_whence = SEEK_SET,
                        .l_start = start, .l_len = len };
    fcntl(fd, F_SETLK, &fl);
}

/* Deadlock-free two-record lock using ordering */
int lock_two_records(int fd, off_t rec1, off_t rec2, off_t recsize) {
    /* Always lock the lower offset first */
    off_t first = (rec1 < rec2) ? rec1 : rec2;
    off_t second = (rec1 < rec2) ? rec2 : rec1;

    struct flock fl = { .l_type = F_WRLCK, .l_whence = SEEK_SET,
                        .l_start = first * recsize, .l_len = recsize };
    if (fcntl(fd, F_SETLKW, &fl) == -1) {
        if (errno == EDEADLK) {
            fprintf(stderr, "Deadlock detected by kernel\n");
            return -1;
        }
        return -1;
    }

    fl.l_start = second * recsize;
    if (fcntl(fd, F_SETLKW, &fl) == -1) {
        if (errno == EDEADLK) {
            /* Release first lock and retry */
            unlock(fd, first * recsize, recsize);
            return -1;
        }
        return -1;
    }

    return 0;  /* both locked */
}

int main(void) {
    int fd = open("data.db", O_RDWR | O_CREAT, 0644);
    if (fd == -1) { perror("open"); return 1; }

    /* Lock records 5 and 3 (ordered: 3 first, then 5) */
    if (lock_two_records(fd, 5, 3, 100) == 0) {
        printf("Both records locked (deadlock-free)\n");
        unlock(fd, 3 * 100, 100);
        unlock(fd, 5 * 100, 100);
    }

    close(fd);
    unlink("data.db");
    return 0;
}

/* Deadlock-free: always lock lower offset first */
void lock_ordered(int fd, off_t a, off_t b, off_t size) {
    off_t first = (a < b) ? a : b;
    off_t second = (a < b) ? b : a;
    struct flock fl = {.l_type=F_WRLCK, .l_whence=SEEK_SET};
    fl.l_start = first * size; fl.l_len = size;
    fcntl(fd, F_SETLKW, &fl);
    fl.l_start = second * size;
    fcntl(fd, F_SETLKW, &fl);
}

