#include <mqueue.h>
#include <stdio.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/wait.h>

#define QUEUE_NAME "/demo_mq"
#define MAX_MSG_SIZE 256
#define MAX_MSGS 10

int main(void) {
    /* Set queue attributes */
    struct mq_attr attr;
    attr.mq_flags = 0;
    attr.mq_maxmsg = MAX_MSGS;
    attr.mq_msgsize = MAX_MSG_SIZE;
    attr.mq_curmsgs = 0;

    /* Create queue */
    mq_unlink(QUEUE_NAME);  /* remove stale queue */
    mqd_t mq = mq_open(QUEUE_NAME, O_CREAT | O_RDWR, 0666, &attr);
    if (mq == (mqd_t)-1) { perror("mq_open"); return 1; }

    pid_t pid = fork();
    if (pid == 0) {
        /* Child: sender */
        mqd_t cmq = mq_open(QUEUE_NAME, O_WRONLY);
        mq_send(cmq, "Low priority", 13, 1);   /* priority 1 */
        mq_send(cmq, "High priority", 14, 10);  /* priority 10 */
        mq_send(cmq, "Medium priority", 16, 5); /* priority 5 */
        mq_close(cmq);
        _exit(0);
    }

    wait(NULL);

    /* Parent: receiver (highest priority first) */
    char buf[MAX_MSG_SIZE + 1];
    unsigned int prio;
    for (int i = 0; i < 3; i++) {
        ssize_t n = mq_receive(mq, buf, MAX_MSG_SIZE, &prio);
        if (n >= 0) {
            buf[n] = '\0';
            printf("Received (prio=%u): %s\n", prio, buf);
        }
    }
    /* Output order: High(10), Medium(5), Low(1) */

    mq_close(mq);
    mq_unlink(QUEUE_NAME);
    return 0;
}

